				try {

	    // histrix 2 method
	    if (class_exists('Histrix_Mail')){

		$htxmailer = new Histrix_Mail($_SESSION['emailUser'], $_SESSION['emailPass']);

		$params = array('from'=> 'fromMail',
				'message'=> "BODY",
				'subj'=> "subject",
				'cc' => 'cc_email',
				'attach'=> "fileAttach",
				'attachArray'=> 'filesArray');

		$htxmailer->send('to_email', $params);


	    } else {

                    $db = $_SESSION["db"];
                    $database = Cache::getCache('datosbase'.$db);

                    require_once '../lib/Swift4/swift_required.php';

                    $smtpServerString = $_SESSION['smtpServer'];

		    $smtp = explode(':',$smtpServerString);
		    $smtpServer = $smtp[0];
		    $smtpPort   = $smtp[1];
		    $protocol   = $smtp[2];

/*                  	  
                    $user       = $_SESSION['emailUser'];
                    $pass       = $_SESSION['emailPass'];
*/
                    $user       = $database->smtpUser;
                    $pass       = $database->smtpPassword;

                    if ($smtpPort == ''){ 
                  	  $smtpPort = 465;
//                  	  $smtpPort = 587;
		    }

		    if ($smtpPort == 465 || $smtpPort == 587){
			$protocol = "ssl";
  		    }

		    $serverstring = $smtpServer.'--'. $smtpPort.'--'. $protocol;
//		    loger($smtpServer.'--'. $smtpPort.'--'. $protocol.'-- user: '.$user.' pass:'.$pass , 'Mail_errors.log');

                    $transport = Swift_SmtpTransport::newInstance($smtpServer, $smtpPort, $protocol)
                    ->setUsername($user)
                    ->setPassword($pass)
                    ;

                    //Create the Mailer using your created Transport
                    $mailer = Swift_Mailer::newInstance($transport);

                    //Create a message
                    $message = Swift_Message::newInstance("subject")
                    ->setFrom( trim("fromMail") )
                    ->setBody("BODY", "text/html");

		    $toemail_dest = str_replace(',' , ';',"to_email");
		    $ccemail_dest = str_replace(',' , ';',"cc_email");


                    if ($toemail_dest != ''){
                        $email_destination = explode(';' , $toemail_dest );
			$email_destination=array_map('trim',$email_destination);
			$message->setTo($email_destination);
                    }


		    if ('chk_enviarmecopia' != '0'){
			$ccemail_dest .= ';fromMail';
			$ccemail_dest = trim(trim($ccemail_dest), ';');
		    }
		    loger($ccemail_dest, 'cc.log');

                    if ($ccemail_dest != ''){
                        $cc_destination = explode(';' , $ccemail_dest );
			$cc_destination=array_map('trim',$cc_destination);
			$message->setCc($cc_destination);
                    }

		    if ('chk_adj' != '0'){
                	if ('fileAttach' != '' ){
                    	    $dirname = '../database/'.$_SESSION['datapath'].'tmp/';
                    	    $message->attach(Swift_Attachment::fromPath($dirname."fileAttach"));
                	}
		    }


		    if ('chkFadj' != '0' ){
                        	loger('chkFadj', 'e-mails.log');

                        if ('filesArray' != ''){
                            $fileList = unserialize(stripslashes('filesArray'));
	                    foreach($fileList as $fileName => $watermark){
                        	if ($watermark != '') 
                    	         $custName = $watermark.'_'.basename($fileName);
                        	else 
                                 $custName = basename($fileName);

                        	loger($fileName, 'e-mails.log');
                        	$message->attach( Swift_Attachment::fromPath($fileName)->setFilename($custName));
                    	    }
                	}
		    }


                    $message->setReadReceiptTo('fromMail');

                    //Pass a variable name TO the send() method
                    if (!$mailer->send($message, $failures))
                    {
//                        echo "Failures:";
                        $log = print_r($failures, true);

                        loger($toemail_dest, 'Mail_errors.log');
                        loger($log, 'Mail_errors.log');

                        $Nheader = 'Error Envio - '.date('H:i:s', time());
                        $Ntext   = 'Error de Envio a '.$serverstring.' '.$toemail_dest.' user:'.$user.' pass:'.$pass.'from fromMail';
			$Ntext   .= print_r($failures, true);
                        loger($Ntext, 'Mail_errors.log');

                        $code[] = "Histrix.notification('Print', {icon:'mail_send.png',title:'$Nheader',text:'$Ntext' })";
                        echo Html::scriptTag($code);

                    } else {

                        $Nheader = 'Envio de correo - '.date('H:i:s', time());
                        $Ntext   = 'Enviado a '.$toemail_dest;
                        $code[] = "Histrix.notification('Send', {icon:'mail_send.png',title:'$Nheader',text:'$Ntext',fade:6000 })";
                        echo Html::scriptTag($code);
                    }

                    // COPY TO SENT FOLDER
                    $server = $database->imapServer;
                    $txtmessage = $message->toString();

                if ($server == 'imap.gmail.com')
                {
                    $user       = $_SESSION['emailUser'];
                    $pass       = $_SESSION['emailPass'];
		    $serverImap = '{imap.gmail.com:993/ssl}';
		    $stream = imap_open( $serverImap, $user, $pass);
		    $imap_result = imap_append($stream, '{imap.gmail.com:993/ssl}[Gmail]/Enviados', $txtmessage);
		    loger(imap_errors(), 'imap.log');
                }
                else
                {
		    if ($server != '') {
			$serverImap = "{".$server."}";
                    $user       = $_SESSION['emailUser'];
                    $pass       = $_SESSION['emailPass'];

			$stream = imap_open( $serverImap."INBOX", $user, $pass);
			@imap_createmailbox($stream, $serverImap."INBOX.Sent");
    			@imap_append($stream, $serverImap."INBOX.Sent", $txtmessage);
		    }
                }
loger("BODY");

	   }



        } catch (Exception $ex){
		header('HTTP/1.1 400 Bad Request');
		echo '<h4>EMAIL NO ENVIADO</h4>';
		echo $serverstring;
		echo $ex->getMessage();
		loger($ex->getMessage(), 'Mail_errors.log');
		die();
    	}
